arguments.argument:
if global.gamePaused=false
{
  //Color change
  if colPhase=0
  {
    colTime-=5
    if colTime<=135 {colPhase=1}
  }
  else if colPhase=1
  {
    colTime+=5
    if colTime>=255 {colPhase=0}
  }
  
  if laserProg=0
  {
    if image_xscale<maxLength {image_xscale+=2}
  }
  else if laserProg=1
  {
    image_xscale-=4
    if image_xscale<=4 {instance_destroy()}
  }
  image_angle-=spinSpd
}
